1154	
1155	// ReadyExecutionBreakdown classifies dependency-ready beads by the reason
1156	// they are NOT execution-eligible: epic containers, retry cooldown,
1157	// execution-eligible=false, or superseded. It's the diagnostic the work loop
1158	// emits when the execution queue is empty but `ddx bead ready` is not.
1159	type ReadyExecutionBreakdown struct {
1160		SkippedEpics       []string
1161		SkippedOnCooldown  []string
1162		SkippedNotEligible []string
1163		SkippedSuperseded  []string
1164		NextRetryAfter     string
1165	}
1166	
1167	func (s *Store) ReadyExecutionBreakdown() (ReadyExecutionBreakdown, error) {
1168		out := ReadyExecutionBreakdown{}
1169		ready, err := s.Ready()
1170		if err != nil {
1171			return out, err
1172		}
1173		now := time.Now().UTC()
1174		var soonestRetry time.Time
1175		for _, b := range ready {
1176			if retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]; ok {
1177				if retryAfterStr, isStr := retryAfterRaw.(string); isStr && retryAfterStr != "" {
1178					if retryAfter, err := time.Parse(time.RFC3339, retryAfterStr); err == nil && retryAfter.After(now) {
1179						out.SkippedOnCooldown = append(out.SkippedOnCooldown, b.ID)
1180						if soonestRetry.IsZero() || retryAfter.Before(soonestRetry) {
1181							soonestRetry = retryAfter
1182						}
1183						continue
1184					}
1185				}
1186			}
1187			if eligible, ok := b.Extra["execution-eligible"]; ok {
1188				if val, isBool := eligible.(bool); isBool && !val {
1189					out.SkippedNotEligible = append(out.SkippedNotEligible, b.ID)
1190					continue
1191				}
1192			}
1193			if sup, ok := b.Extra["superseded-by"]; ok {
1194				if s, isStr := sup.(string); isStr && s != "" {
1195					out.SkippedSuperseded = append(out.SkippedSuperseded, b.ID)
1196					continue
1197				}
1198			}
1199		}
1200		if !soonestRetry.IsZero() {
1201			out.NextRetryAfter = soonestRetry.Format(time.RFC3339)
1202		}
1203		return out, nil
1204	}
1205	
1206	func (s *Store) readyFiltered(executionOnly bool) ([]Bead, error) {
1207		beads, err := s.ReadAll()
1208		if err != nil {
1209			return nil, err
1210		}
1211		statusMap := make(map[string]string)
1212		for _, b := range beads {
1213			statusMap[b.ID] = b.Status
1214		}
1215	
1216		var ready []Bead
1217		for _, b := range beads {
1218			if b.Status != StatusOpen {
1219				// Surface stalled in_progress beads so a fresh worker can
1220				// reclaim them atomically in Claim().
1221				if executionOnly && b.Status == StatusInProgress && heartbeatIsStale(b.Extra) {
1222					// fall through to dependency check below
1223				} else {
1224					continue
1225				}
1226			}
1227			allSatisfied := true
1228			for _, depID := range b.DepIDs() {
1229				if statusMap[depID] != StatusClosed {
1230					allSatisfied = false
1231					break
1232				}
1233			}
1234			if !allSatisfied {
1235				continue
1236			}
1237			if executionOnly {
1238				// Filter by execution-eligible (default true if absent)
1239				eligible, ok := b.Extra["execution-eligible"]
1240				if ok {
1241					if val, isBool := eligible.(bool); isBool && !val {
1242						continue
1243					}
1244				}
1245				// Filter out superseded beads
1246				if sup, ok := b.Extra["superseded-by"]; ok {
1247					if s, isStr := sup.(string); isStr && s != "" {
1248						continue
1249					}
1250				}
1251				if retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]; ok {
1252					if retryAfterStr, isStr := retryAfterRaw.(string); isStr && retryAfterStr != "" {
1253						if retryAfter, err := time.Parse(time.RFC3339, retryAfterStr); err == nil && retryAfter.After(time.Now().UTC()) {
1254							continue
1255						}
1256					}
1257				}
1258			}
1259			ready = append(ready, b)
1260		}
1261	
1262		sortBeadsForQueue(ready)
1263	
1264		return ready, nil
1265	}
1266	
1267	// Blocked returns open beads with at least one unclosed dependency.
1268	func (s *Store) Blocked() ([]Bead, error) {
1269		beads, err := s.ReadAll()
1270		if err != nil {
1271			return nil, err
1272		}
1273		statusMap := make(map[string]string)
1274		for _, b := range beads {
1275			statusMap[b.ID] = b.Status
1276		}
1277	
1278		var blocked []Bead
1279		for _, b := range beads {
1280			if b.Status != StatusOpen {
1281				continue
1282			}
1283			for _, depID := range b.DepIDs() {
1284				if statusMap[depID] != StatusClosed {
1285					blocked = append(blocked, b)
1286					break
1287				}
1288			}
1289		}
1290		sortBeadsForQueue(blocked)
1291		return blocked, nil
1292	}
1293	
1294	// BlockedAll returns open beads that are currently not runnable, classified
1295	// by blocker kind. Dependency-blocked beads are emitted first (any unclosed
1296	// dep in their DAG); retry-parked beads whose execute-loop-retry-after is in
1297	// the future are emitted with blocker kind BlockerKindRetryCooldown. A bead
1298	// that is both dep-blocked and cooldown-parked is reported as dependency-
1299	// blocked, because deps are the stronger blocker.
1300	func (s *Store) BlockedAll() ([]BlockedBead, error) {
1301		beads, err := s.ReadAll()
1302		if err != nil {
1303			return nil, err
1304		}
1305		statusMap := make(map[string]string)
1306		for _, b := range beads {
1307			statusMap[b.ID] = b.Status
1308		}
1309	
1310		now := time.Now().UTC()
1311		var entries []BlockedBead
1312		for _, b := range beads {
1313			if b.Status != StatusOpen {
1314				continue
1315			}
1316	
1317			var unclosed []string
1318			for _, depID := range b.DepIDs() {
1319				if statusMap[depID] != StatusClosed {
1320					unclosed = append(unclosed, depID)
1321				}
1322			}
1323			if len(unclosed) > 0 {
1324				entries = append(entries, BlockedBead{
1325					Bead: b,
1326					Blocker: Blocker{
1327						Kind:           BlockerKindDependency,
1328						UnclosedDepIDs: unclosed,
1329					},
1330				})
1331				continue
1332			}
1333	
1334			retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]
1335			if !ok {
1336				continue
1337			}
1338			retryAfterStr, isStr := retryAfterRaw.(string)
1339			if !isStr || retryAfterStr == "" {
1340				continue
1341			}
1342			retryAfter, err := time.Parse(time.RFC3339, retryAfterStr)
1343			if err != nil || !retryAfter.After(now) {
1344				continue
1345			}
1346			blocker := Blocker{
1347				Kind:           BlockerKindRetryCooldown,
1348				NextEligibleAt: retryAfter.UTC().Format(time.RFC3339),
1349			}
1350			if v, ok := b.Extra["execute-loop-last-status"]; ok {
1351				if s, ok := v.(string); ok {
1352					blocker.LastStatus = s
1353				}
1354			}
1355			if v, ok := b.Extra["execute-loop-last-detail"]; ok {
1356				if s, ok := v.(string); ok {
1357					blocker.LastDetail = s
1358				}
1359			}
1360			entries = append(entries, BlockedBead{
1361				Bead:    b,
1362				Blocker: blocker,
1363			})
1364		}
1365	
1366		sort.SliceStable(entries, func(i, j int) bool {
1367			if entries[i].Priority != entries[j].Priority {
1368				return entries[i].Priority < entries[j].Priority
1369			}
1370			if !entries[i].CreatedAt.Equal(entries[j].CreatedAt) {
1371				return entries[i].CreatedAt.Before(entries[j].CreatedAt)
1372			}
1373			return entries[i].ID < entries[j].ID
1374		})
1375		return entries, nil
1376	}
1377	
1378	func sortBeadsForQueue(beads []Bead) {
1379		sort.SliceStable(beads, func(i, j int) bool {
1380			if beads[i].Priority != beads[j].Priority {
1381				return beads[i].Priority < beads[j].Priority
1382			}
1383			if !beads[i].CreatedAt.Equal(beads[j].CreatedAt) {
1384				return beads[i].CreatedAt.Before(beads[j].CreatedAt)
1385			}
1386			return beads[i].ID < beads[j].ID
1387		})
1388	}
1389	
1390	// Status returns aggregate counts.
1391	func (s *Store) Status() (*StatusCounts, error) {
1392		beads, err := s.ReadAll()
1393		if err != nil {
1394			return nil, err
1395		}
1396		ready, err := s.Ready()
1397		if err != nil {
1398			return nil, err
1399		}
1400		blocked, err := s.Blocked()
1401		if err != nil {
1402			return nil, err
1403		}
1404	
1405		counts := &StatusCounts{Total: len(beads), Ready: len(ready), Blocked: len(blocked)}
1406		for _, b := range beads {
1407			switch b.Status {
1408			case StatusOpen:
1409				counts.Open++
1410			case StatusClosed:
1411				counts.Closed++
1412			}
1413		}
1414		return counts, nil
1415	}
1416	
1417	// DepAdd adds a dependency: id depends on depID.
1418	func (s *Store) DepAdd(id, depID string) error {
1419		return s.WithLock(func() error {
1420			beads, _, err := s.readAllLatestRaw()
1421			if err != nil {
1422				return err
1423			}
1424			var target *Bead
1425			depExists := false
1426			for i := range beads {
1427				if beads[i].ID == id {
1428					target = &beads[i]
1429				}
1430				if beads[i].ID == depID {
1431					depExists = true
1432				}
1433			}
1434			if target == nil {
1435				return fmt.Errorf("bead: not found: %s", id)
1436			}
1437			if !depExists {
1438				return fmt.Errorf("bead: dependency not found: %s", depID)
1439			}
1440			if id == depID {
1441				return fmt.Errorf("bead: cannot depend on self")
1442			}
1443			if target.HasDep(depID) {
1444				return nil // already exists
1445			}
1446	
1447			// Check for circular dependency
1448			depMap := make(map[string][]string)
1449			for _, b := range beads {
1450				depMap[b.ID] = b.DepIDs()
1451			}
1452			depMap[id] = append(append([]string{}, target.DepIDs()...), depID)
1453			if hasCycle(depMap, id) {
1454				return fmt.Errorf("bead: circular dependency: %s -> %s", id, depID)
1455			}
1456	
1457			target.AddDep(depID, "blocks")
1458			target.UpdatedAt = time.Now().UTC()
1459			return s.WriteAll(beads)
1460		})
1461	}
1462	
1463	// DepRemove removes a dependency.
1464	func (s *Store) DepRemove(id, depID string) error {
1465		return s.Update(id, func(b *Bead) {
1466			b.RemoveDep(depID)
1467		})
1468	}
1469	
1470	// DepTree returns a text representation of the dependency tree.
1471	func (s *Store) DepTree(rootID string) (string, error) {
1472		beads, err := s.ReadAll()
1473		if err != nil {
1474			return "", err
1475		}
1476		byID := make(map[string]*Bead)
1477		for i := range beads {
1478			byID[beads[i].ID] = &beads[i]
1479		}
1480	
1481		if rootID != "" {
1482			target, ok := byID[rootID]
1483			if !ok {
1484				return "", fmt.Errorf("bead: not found: %s", rootID)
1485			}
1486			var sb strings.Builder
1487			// Walk up: show the dependency chain (what this node depends on)
1488			depChain := s.depChainUp(byID, rootID)
1489			if len(depChain) > 0 {
1490				// Print deps as the tree root(s), with the target as their child
1491				for _, depID := range depChain {
1492					if dep, ok := byID[depID]; ok {
1493						fmt.Fprintf(&sb, "%s [%s] %s\n", dep.ID, dep.Status, dep.Title)
1494					}
1495				}
1496			}
1497			// Print the target node
1498			fmt.Fprintf(&sb, "%s [%s] %s\n", target.ID, target.Status, target.Title)
1499			// Print dependents (what depends on this node)
1500			var children []string
1501			for _, other := range sortedKeys(byID) {
1502				if byID[other].HasDep(rootID) {
1503					children = append(children, other)
1504				}
1505			}
1506			for _, child := range children {
1507				s.printTree(&sb, byID, child, "  ", true)
1508			}
1509			return sb.String(), nil
1510		}
1511	
1512		// Find roots (beads that have no dependencies themselves)
1513		var roots []string
1514		for _, b := range beads {
1515			if len(b.Dependencies) == 0 {
1516				roots = append(roots, b.ID)
1517			}
1518		}
1519		sort.Strings(roots)
1520	
1521		var sb strings.Builder
1522		for i, root := range roots {
1523			s.printTree(&sb, byID, root, "", i == len(roots)-1)
1524		}
1525		return sb.String(), nil
1526	}
1527	
1528	func (s *Store) printTree(sb *strings.Builder, byID map[string]*Bead, id, prefix string, last bool) {
1529		b, ok := byID[id]
1530		if !ok {
1531			return
1532		}
1533	
1534		connector := "├── "
1535		if last {
1536			connector = "└── "
1537		}
1538		if prefix == "" {
1539			connector = ""
1540		}
1541	
1542		fmt.Fprintf(sb, "%s%s%s [%s] %s\n", prefix, connector, b.ID, b.Status, b.Title)
1543	
1544		// Find beads that depend on this one (children in the tree)
1545		var children []string
1546		for _, other := range sortedKeys(byID) {
1547			if byID[other].HasDep(id) {
1548				children = append(children, other)
1549			}
1550		}
1551	
1552		childPrefix := prefix
1553		if prefix != "" {
1554			if last {
1555				childPrefix += "    "
1556			} else {
1557				childPrefix += "│   "
1558			}
1559		}
1560	
1561		for i, child := range children {
1562			s.printTree(sb, byID, child, childPrefix, i == len(children)-1)
1563		}
1564	}
1565	
1566	// depChainUp returns the direct dependencies of a bead (upstream IDs).
1567	func (s *Store) depChainUp(byID map[string]*Bead, id string) []string {
1568		b, ok := byID[id]
1569		if !ok {
1570			return nil
1571		}
1572		return b.DepIDs()
1573	}
1574	
1575	// validateBead checks core invariants that must hold for any bead (create or update).
1576	func (s *Store) validateBead(b *Bead) error {
1577		if strings.TrimSpace(b.Title) == "" {
1578			return fmt.Errorf("bead: title is required")
1579		}
1580		if b.Priority < MinPriority || b.Priority > MaxPriority {
1581			return fmt.Errorf("bead: priority must be %d-%d, got %d", MinPriority, MaxPriority, b.Priority)
1582		}
1583		if b.Status != StatusOpen && b.Status != StatusInProgress && b.Status != StatusClosed && b.Status != StatusBlocked {
1584			return fmt.Errorf("bead: invalid status: %s", b.Status)
1585		}
1586		// Self-ref check
1587		for _, depID := range b.DepIDs() {
1588			if depID == b.ID && b.ID != "" {
1589				return fmt.Errorf("bead: cannot depend on self")
1590			}
1591		}
1592		return nil
1593	}
1594	
1595	// detectPrefix derives the bead ID prefix from the repository/directory name,
1596	// following the bd convention (e.g., repo "my-project" → prefix "my-project").
1597	// workingDir is the project root to use for git commands; when empty the
1598	// process working directory is used (legacy behaviour, prone to worktree
1599	// path contamination). Falls back to DefaultPrefix if detection fails.
1600	func detectPrefix(workingDir string) string {
1601		// Try git repo root name first, running from the known project root so
1602		// that linked worktrees (e.g. execute-bead isolated worktrees) do not
1603		// contaminate the prefix with their ephemeral directory names.
1604		cmd := gitpkg.Command(context.Background(), workingDir, "rev-parse", "--show-toplevel")
1605		if out, err := cmd.Output(); err == nil {
1606			root := strings.TrimSpace(string(out))
1607			if root != "" {
1608				return filepath.Base(root)
1609			}
1610		}
1611		// Fall back to the provided working dir, then cwd.
1612		if workingDir != "" {
1613			return filepath.Base(workingDir)
1614		}
1615		if wd, err := os.Getwd(); err == nil {
1616			return filepath.Base(wd)
1617		}
1618		return DefaultPrefix
1619	}
1620	
1621	func parseDurationOr(envKey string, fallback time.Duration) time.Duration {
1622		v := os.Getenv(envKey)
1623		if v == "" {
1624			return fallback
1625		}
1626		// Try as seconds (plain number)
1627		if secs, err := strconv.ParseFloat(v, 64); err == nil {
1628			return time.Duration(secs * float64(time.Second))
1629		}
1630		// Try as Go duration
1631		if d, err := time.ParseDuration(v); err == nil {
1632			return d
1633		}
1634		return fallback
1635	}
1636	
1637	func envOr(key, fallback string) string {
1638		if v := os.Getenv(key); v != "" {
1639			return v
1640		}
1641		return fallback
1642	}
1643	
1644	func containsString(ss []string, s string) bool {
1645		for _, v := range ss {
1646			if v == s {
1647				return true
1648			}
1649		}
1650		return false
1651	}
1652	
1653	func sortedKeys(m map[string]*Bead) []string {
1654		keys := make([]string, 0, len(m))
1655		for k := range m {
1656			keys = append(keys, k)
1657		}
1658		sort.Strings(keys)
1659		return keys
1660	}
1661	
1662	// hasCycle detects cycles in the dependency graph starting from startID.
1663	func hasCycle(deps map[string][]string, startID string) bool {
1664		visited := make(map[string]bool)
1665		stack := make(map[string]bool)
1666	
1667		var visit func(string) bool
1668		visit = func(id string) bool {
1669			visited[id] = true
1670			stack[id] = true
1671	
1672			for _, dep := range deps[id] {
1673				if !visited[dep] {
1674					if visit(dep) {
1675						return true
1676					}
1677				} else if stack[dep] {
1678					return true
1679				}
1680			}
1681	
1682			stack[id] = false
1683			return false
1684		}
1685	
1686		return visit(startID)
1687	}
1688

1	package bead
2	
3	import (
4		"fmt"
5		"os"
6		"path/filepath"
7		"strconv"
8		"strings"
9		"time"
10	)
11	
12	// StaleLockAge is the duration after which a lock is considered stale
13	// and can be forcibly broken. Default: 2 hours.
14	var StaleLockAge = 2 * time.Hour
15	
16	// WithLock acquires the file lock, runs fn, then releases the lock.
17	// For external backends, locking is delegated to the backend tool.
18	func (s *Store) WithLock(fn func() error) error {
19		if s.backend != nil {
20			return s.backend.WithLock(fn)
21		}
22		if err := s.acquireLock(); err != nil {
23			return err
24		}
25		defer s.releaseLock()
26		return fn()
27	}
28	
29	func (s *Store) acquireLock() error {
30		if err := os.MkdirAll(s.Dir, 0o755); err != nil {
31			return fmt.Errorf("bead: lock dir: %w", err)
32		}
33	
34		deadline := time.Now().Add(s.LockWait)
35		for {
36			err := os.Mkdir(s.LockDir, 0o755)
37			if err == nil {
38				// Write PID and acquired_at
39				_ = os.WriteFile(filepath.Join(s.LockDir, "pid"),
40					[]byte(fmt.Sprintf("%d", os.Getpid())), 0o644)
41				_ = os.WriteFile(filepath.Join(s.LockDir, "acquired_at"),
42					[]byte(time.Now().UTC().Format(time.RFC3339)), 0o644)
43				return nil
44			}
45	
46			// Check for stale lock
47			if s.breakStaleLock() {
48				continue // retry immediately after breaking
49			}
50	
51			if time.Now().After(deadline) {
52				owner := "unknown"
53				pidData, _ := os.ReadFile(filepath.Join(s.LockDir, "pid"))
54				if len(pidData) > 0 {
55					owner = strings.TrimSpace(string(pidData))
56				}
57				return fmt.Errorf("bead: lock timeout (owner pid: %s)", owner)
58			}
59			time.Sleep(50 * time.Millisecond)
60		}
61	}
62	
63	// breakStaleLock checks if the existing lock is stale (owner dead or too old)
64	// and breaks it if so. Returns true if lock was broken.
65	func (s *Store) breakStaleLock() bool {
66		// Check if owner PID is still alive (skip if it's our own PID)
67		pidData, err := os.ReadFile(filepath.Join(s.LockDir, "pid"))
68		if err == nil {
69			pid, err := strconv.Atoi(strings.TrimSpace(string(pidData)))
70			if err == nil && pid > 0 && pid != os.Getpid() {
71				if !processAlive(pid) {
72					// Process is dead — break the lock
73					os.RemoveAll(s.LockDir)
74					return true
75				}
76			}
77		}
78	
79		// Check age
80		acquiredData, err := os.ReadFile(filepath.Join(s.LockDir, "acquired_at"))
81		if err == nil {
82			acquired, err := time.Parse(time.RFC3339, strings.TrimSpace(string(acquiredData)))
83			if err == nil && time.Since(acquired) > StaleLockAge {
84				os.RemoveAll(s.LockDir)
85				return true
86			}
87		}
88	
89		return false
90	}
91	
92	func (s *Store) releaseLock() {
93		os.RemoveAll(s.LockDir)
94	}
95

1	package bead
2	
3	import (
4		"encoding/json"
5		"fmt"
6		"os/exec"
7		"strings"
8	)
9	
10	// ExternalBackend delegates storage to an external tool (bd or br).
11	type ExternalBackend struct {
12		Tool       string // "bd" or "br"
13		Collection string
14	}
15	
16	// NewExternalBackend creates a backend that shells out to the given tool.
17	func NewExternalBackend(tool, collection string) (*ExternalBackend, error) {
18		if _, err := exec.LookPath(tool); err != nil {
19			return nil, fmt.Errorf("bead: backend %s not found in PATH", tool)
20		}
21		return &ExternalBackend{Tool: tool, Collection: collection}, nil
22	}
23	
24	// Init is a no-op for external backends — they manage their own storage.
25	func (e *ExternalBackend) Init() error {
26		return nil
27	}
28	
29	// ReadAll lists all beads from the external tool.
30	func (e *ExternalBackend) ReadAll() ([]Bead, error) {
31		cmd := exec.Command(e.Tool, "list", "--json")
32		output, err := cmd.Output()
33		if err != nil {
34			return nil, fmt.Errorf("bead: %s list --json: %w", e.Tool, err)
35		}
36	
37		trimmed := strings.TrimSpace(string(output))
38		if trimmed == "" || trimmed == "[]" {
39			return nil, nil
40		}
41	
42		// Try JSON array first
43		if strings.HasPrefix(trimmed, "[") {
44			var raw []json.RawMessage
45			if err := json.Unmarshal([]byte(trimmed), &raw); err != nil {
46				return nil, fmt.Errorf("bead: %s parse: %w", e.Tool, err)
47			}
48			var beads []Bead
49			for _, r := range raw {
50				b, err := unmarshalBead(r)
51				if err != nil {
52					continue
53				}
54				beads = append(beads, b)
55			}
56			return beads, nil
57		}
58	
59		// JSONL fallback
60		var beads []Bead
61		for _, line := range strings.Split(trimmed, "\n") {
62			line = strings.TrimSpace(line)
63			if line == "" {
64				continue
65			}
66			b, err := unmarshalBead([]byte(line))
67			if err != nil {
68				continue
69			}
70			beads = append(beads, b)
71		}
72		return beads, nil
73	}
74	
75	// WriteAll writes all beads back via the external tool.
76	// For bd/br, we export as JSONL and import. This is a full replace.
77	func (e *ExternalBackend) WriteAll(beads []Bead) error {
78		// Build JSONL
79		var sb strings.Builder
80		for _, b := range beads {
81			data, err := marshalBead(b)
82			if err != nil {
83				return fmt.Errorf("bead: marshal for %s: %w", e.Tool, err)
84			}
85			sb.Write(data)
86			sb.WriteByte('\n')
87		}
88	
89		// Pipe to tool's import command
90		cmd := exec.Command(e.Tool, "import", "--from", "jsonl", "--replace", "-")
91		cmd.Stdin = strings.NewReader(sb.String())
92		if output, err := cmd.CombinedOutput(); err != nil {
93			return fmt.Errorf("bead: %s import: %s: %w", e.Tool, string(output), err)
94		}
95		return nil
96	}
97	
98	// WithLock for external backends is a no-op — the tool handles its own locking.
99	func (e *ExternalBackend) WithLock(fn func() error) error {
100		return fn()
101	}
